/** {@inheritDoc} */
public OpenMapRealVector ebeDivide(RealVector v) {
    checkVectorDimensions(v.getDimension());
    OpenMapRealVector res = new OpenMapRealVector(this);
    // Create a copy of the keys to avoid ConcurrentModificationException
    int[] keys = new int[res.entries.size()];
    double[] values = new double[res.entries.size()];
    Iterator iter = res.entries.iterator();
    int i = 0;
    while (iter.hasNext()) {
        iter.advance();
        keys[i] = iter.key();
        values[i] = iter.value() / v.getEntry(iter.key());
        i++;
    }

    // Now apply all the changes
    for (int j = 0; j < keys.length; j++) {
        res.setEntry(keys[j], values[j]);
    }
    return res;
}

