import org.apache.commons.math.linear.OpenMapRealVector;
import org.apache.commons.math.linear.RealVector;

public class TestFix {
    public static void main(String[] args) {
        try {
            System.out.println("Testing ebeMultiply and ebeDivide fixes...");

            // Create sparse vectors that would trigger the ConcurrentModificationException
            OpenMapRealVector u = new OpenMapRealVector(3);
            u.setEntry(0, 1.0);
            u.setEntry(2, 2.0);

            OpenMapRealVector v = new OpenMapRealVector(3);
            v.setEntry(1, 3.0);

            System.out.println("Created vectors u and v");

            // Test ebeMultiply - this should not throw ConcurrentModificationException
            System.out.println("Testing ebeMultiply...");
            RealVector w = u.ebeMultiply(v);
